ce degradation when factorizing the same natural numbers multiple times. However, the amount of data to be cached depends on the use case. To address this, how about implementing an LRU cache class using `OrderedDict`, allowing the user to define the cache size?

Additionally, I thought it would be useful to query prime factors from `factordb` using `requests`, but since this would require the `requests` library, further consideration is needed.

```python
from bisect import bisect
from collections import OrderedDict
from typing import Iterable
from warnings import warn
from sympy.external import import_module
from sympy.external.gmpy import remove
from sympy.ntheory import sieve, isprime

class FactorCache:
    def __init__(self, use_factordb:bool=False, maxsize:int|None=None):
        self._cache: OrderedDict[int, int] = OrderedDict()
        self.use_factordb = use_factordb
        self.maxsize = maxsize

    FACTORDB_URL = "http://factordb.com/api"

    @property
    def use_factordb(self) -> bool:
        return self._requests is not None

    @use_factordb.setter
    def use_factordb(self, value: bool) -> None:
        if value:
            self._requests = import_module("requests", warn_not_installed=True)
        else:
            self._requests = None

    @property
    def maxsize(self) -> int | None:
        return self._maxsize

    @maxsize.setter
    def maxsize(self, value: int | None) -> None:
        if value is not None and value <= 0:
            raise ValueError("value must be None or a positive integer")
        self._maxsize = value
        if value is not None:
            while len(self._cache) > value:
                self._cache.popitem(False)

    def clear(self) -> None:
        self._cache = OrderedDict()

    def add_factors(self, n:int, factors:Iterable[int]) -> None:
        if n < 2:
            return

        def _add_new_item(k:int, v:int) -> None:
            self._cache[k] = v
            if self.maxsize is not None and len(self._cache) > self.maxsize:
                self._cache.popitem(False)

        for factor in sorted(set(factors), reverse=True):
            if n == factor:
                if isprime(factor):
                    _add_new_item(n, 1)
                    return
                continue
            if factor <= 1 or n % factor or not isprime(factor):
                continue
            if n in self._cache:
                self._cache[n] = max(self._cache[n], factor)
            else:
                _add_new_item(n, factor)
            n, _ = remove(n, factor)
            n = int(n)
        return

    def get(self, n: int) -> tuple[dict[int, int], int]:
        factors: dict[int, int] = {}
        while n > 1:
            if sieve._list[bisect(sieve._list, n) - 1] == n:
                # If it exists in sieve
                factors[n] = 1
                n = 1
                break
            if n in self._cache:
                # If it exists in cache
                self._cache.move_to_end(n)
                p = self._cache[n]
                if p == 1:
                    # prime
                    factors[n] = 1
                    n = 1
                    break
                n, e = remove(n, p)
                factors[p] = e
                continue
            if self.use_factordb:
                res = self._requests.get(FactorCache.FACTORDB_URL, params={"query": str(n)})
                if res.status_code != self._requests.codes.ok:
                    warn("Not used because it does not connect to factordb")
                    self.use_factordb = False
                    break
                j = res.json()
                if j.get("status") == "FF":
                    for p, e in j.get("factors"):
                        factors[int(p)] = int(e)
                    self.add_factors(n, factors.keys())
                    n = 1
                    break
                else:
                    break
            break
        return factors, n

factor_cache = FactorCache(maxsize=1024)
